INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('retired-d0d1b9a2-moex-00020', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-114-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '乙公司X1年1月1日與X1年12月31日應收帳款餘額分別為$199,000及$213,000，其帳齡分 析表如下： 帳齡 應收帳款金額 損失比率 30天以下 $175,000 1% 31-90天 $30,000 5% 90天以上 $8,000 12% 合計 $213,000 備抵損失在期末調整之前有貸方餘額$2,000，乙公司X1年應認列之預期信用減損損失（呆帳費 用）應為：', '["$2,000", "$2,210", "$4,210", "$6,210"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:10+00:00", "source_pdf_sha1": "c5c11cd70750", "answer_pdf_sha1": "3e11c2341c06", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "136", "s": "1604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00021', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-114-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年初以每股$150買入乙公司股票2,000股，至X2年底均未出售。甲公司將該股票 分類為透過損益按公允價值衡量之權益工具投資。X1年12月31日和X2年12月31日乙公司 股價分別為$130及$200，請問該投資對甲公司X2年度淨利的影響金額為多少？', '["減少$40,000", "增加$60,000", "增加$100,000", "增加$140,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:10+00:00", "source_pdf_sha1": "c5c11cd70750", "answer_pdf_sha1": "3e11c2341c06", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "136", "s": "1604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00022', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-114-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '大大公司於X1年1月1日發行普通股50,000股，每股面額$10，發行價格每股$20。X2年3月 1日以每股$25買回3,000股庫藏股票，4月2日以每股$22出售庫藏股票1,000股，5月3日註 銷剩餘庫藏股2,000股。請問大大公司X2年度的庫藏股票相關交易對X2年12月31日資產負 債表之權益數影響為何？', '["權益增加$2,000", "權益減少$15,000", "權益減少$40,000", "權益減少$53,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:10+00:00", "source_pdf_sha1": "c5c11cd70750", "answer_pdf_sha1": "3e11c2341c06", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "136", "s": "1604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00023', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-114-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '天天公司於X1年1月1日購買機器設備，成本$480,000，因符合政府補助之規定，購買時由政 府直接撥付一半價款$240,000予機器供應商。此機器設備耐用年限為4年，估計無殘值，並採直 線法提列折舊。天天公司X1年度損益表應認列之政府補助利益為何？', '["$0", "$60,000", "$120,000", "$240,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:10+00:00", "source_pdf_sha1": "c5c11cd70750", "answer_pdf_sha1": "3e11c2341c06", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "136", "s": "1604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00024', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-114-13504c0c', 'sub-retired-d0d1b9a2-02', NULL, 'single_choice', '下列文句「」中用詞，何者最為妥切？', '["好友已值「從心所欲」之年，是拚搏事業的好時機", "土耳其大地震，死傷人數慘重，令人「忍俊不住」", "王生誤解了李生的好意，慚愧的登門「負荊請罪」", "他們兄弟感情深厚，真是「舉案齊眉」，令人稱羨"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:10+00:00", "source_pdf_sha1": "8e2479f19be0", "answer_pdf_sha1": "59c0340c3c3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "136", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00025', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-114-13504c0c', 'sub-retired-d0d1b9a2-02', NULL, 'single_choice', '「樹上的花是小說，有枝有幹地攀在縱橫交叉的結構上，那裡面有多層次、多角度 的說不盡的故事。草花是詩，由於矮，像是剛從土裡蹦上來的，一種精粹的、鮮艷 的、凝聚的、集中的美。散文是爬籐花，都有一種走到那裡就開到那裡的渾灑。如 果有什麼花可以稱之為舞台劇的，大概就是曇花了吧。它是一種徹底的時間藝術， 在絲帷的開闔間即生而即死。」 根據上文，下列選項，何者最接近文意？', '["小說是高高在上，像樹上的花必須仰望", "詩則俯拾即是，就像草花一樣隨處可見", "散文必須像爬籐，要旅行才能寫得渾灑", "舞台劇如曇花，在開幕謝幕間展演人生"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:10+00:00", "source_pdf_sha1": "8e2479f19be0", "answer_pdf_sha1": "59c0340c3c3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "136", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00026', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-114-13504c0c', 'sub-retired-d0d1b9a2-02', NULL, 'single_choice', '「最有名的顯性遺傳疾病，莫過於杭丁頓舞蹈症（Huntington''s Disease）。這是一 種異常殘酷的疾病，患者通常要到四、五十歲才會發病。發病後，病人的中樞神經 系統會慢慢退化、肌肉無力、四肢協調性變差，慢慢喪失記憶，性情和行為發生改 變、喪失高層認知功能、癱瘓、進入植物人狀態，最後昏迷、死亡。上述的退化過 程極為緩慢，大約要五到十年，目前沒有任何藥物或任何療法可以減緩病程發展。 病人和摯愛的家人完全無能為力，只能眼睜睜看著這一切發生。」 關於杭丁頓舞蹈症的敘述，下列何者正確？', '["是隱性遺傳疾病，沒有藥物能治療或預防", "發病後會緩慢漸進式退化，病人較能因應", "屬於腦神經系統退化的疾病，發病後即將失去記憶", "病患的家屬，只能眼睜睜看著病人退化而無力挽救"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:10+00:00", "source_pdf_sha1": "8e2479f19be0", "answer_pdf_sha1": "59c0340c3c3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "136", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00027', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-114-13504c0c', 'sub-retired-d0d1b9a2-02', NULL, 'single_choice', '下列文句，存在語病的是：', '["儘管比賽前他受了點傷，但比賽時依舊所向披靡", "參加試鏡者很少，我得用盡心力才能爭取到角色", "這些八卦新聞經過查證後，實屬空穴來風", "他被債務逼得走投無路，不得不鋌而走險"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:10+00:00", "source_pdf_sha1": "8e2479f19be0", "answer_pdf_sha1": "59c0340c3c3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "136", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00028', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-114-13504c0c', 'sub-retired-d0d1b9a2-02', NULL, 'single_choice', '「一座臨水的扇面小亭，每當夜深人靜，清風徐來，明月當空，水天上下相映，好 一派清淨幽寂，小亭以蘇軾詞中『與誰同坐，明月清風我』句，取名為『與誰同坐 軒』。」 根據上文，此亭取名「與誰同坐軒」的原因為何？', '["此亭清幽能讓人興起飄飄欲仙之感", "明月與清風正好是臨水小亭的特色", "感念蘇軾的儒雅風采渴望與其同坐", "美景當前總讓人傷嘆無知己可共賞"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:10+00:00", "source_pdf_sha1": "8e2479f19be0", "answer_pdf_sha1": "59c0340c3c3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "136", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00029', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-114-13504c0c', 'sub-retired-d0d1b9a2-02', NULL, 'single_choice', '「尚樸的日本茶道愛好者早在數百年前便推崇侘寂之道，珍視器皿製造過程中無心 造就的不完美，追求『碗碗有瑕，各瑕不同』的美學，認為每個茶碗的獨特缺陷恰 好賦予其無法模仿的『個性』；宋代鑑賞家與文人認為開片（瓷器釉面自然龜裂的 現象）最符合審美原則，因為其效果『非人工做作，而是從材質與技法之中自然生 發而成。』」 根據上文，下列選項何者正確？', '["日本茶道推崇的侘寂之道即宋代的品茶審美之道", "侘寂之道強調簡樸美學，格外注重器皿製造材質", "宋代瓷器製造技術尚未成熟，才會經常出現「開片」效果", "日本茶道愛好者與宋代鑑賞家均注重難以複製的缺陷之美"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:10+00:00", "source_pdf_sha1": "8e2479f19be0", "answer_pdf_sha1": "59c0340c3c3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "136", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL)
